         return subtotal + (subtotal * taxRate);
     }

     public decimal ApplyDiscount(decimal price, decimal discountPercent)
     {
         if (discountPercent < 0 || discountPercent > 100)
             throw new ArgumentOutOfRangeException(nameof(discountPercent));

