using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // ──────────────────────────────────────────────
    // CreateOrder — Happy Path
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 10.00m, Quantity = 1 },
            new() { ProductName = "Beta",  Price = 5.50m,  Quantity = 3 },
            new() { ProductName = "Gamma", Price = 2.25m,  Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        // Total = (10*1) + (5.5*3) + (2.25*4) = 10 + 16.5 + 9 = 35.50
        Assert.AreEqual(35.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Clock", Price = 20.00m, Quantity = 1 }
        };
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-3", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}.");
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Pen", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-4", items);
        var order2 = _sut.CreateOrder("cust-4", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_StoresOrderInternally()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Book", Price = 15.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-5", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    // ──────────────────────────────────────────────
    // CreateOrder — Edge / Error Cases
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 5.00m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-6", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-7", items));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    [DataRow(1, 100.00, 100.00, DisplayName = "Quantity 1")]
    [DataRow(5, 3.50, 17.50, DisplayName = "Quantity 5")]
    [DataRow(10, 0.99, 9.90, DisplayName = "Quantity 10")]
    public void CreateOrder_VariousQuantities_CalculatesTotalCorrectly(
        int quantity, double price, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-param", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    // ──────────────────────────────────────────────
    // GetOrder
    // ──────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Lamp", Price = 25.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-8", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-8", result.CustomerId);
        Assert.AreEqual(25.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_EmptyStore_ReturnsNull()
    {
        // Act  (no orders created)
        var result = _sut.GetOrder("any-id");

        // Assert
        Assert.IsNull(result);
    }

    // ──────────────────────────────────────────────
    // GetOrdersByCustomer
    // ──────────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOneOrder_ReturnsSingleOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Desk", Price = 200.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-9", items);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-9");

        // Assert
        Assert.AreEqual(1, results.Count);
        Assert.AreEqual(created.Id, results[0].Id);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        // Arrange — create order for a different customer
        var items = new List<OrderItem>
        {
            new() { ProductName = "Chair", Price = 80.00m, Quantity = 1 }
        };
        _sut.CreateOrder("other-customer", items);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-10");

        // Assert
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrdersSameCustomer_ReturnsAll()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Mouse", Price = 30.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Keyboard", Price = 75.00m, Quantity = 1 }
        };
        var items3 = new List<OrderItem>
        {
            new() { ProductName = "Monitor", Price = 400.00m, Quantity = 1 }
        };

        var order1 = _sut.CreateOrder("cust-11", items1);
        var order2 = _sut.CreateOrder("cust-11", items2);
        var order3 = _sut.CreateOrder("cust-11", items3);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-11");

        // Assert
        Assert.AreEqual(3, results.Count);
        CollectionAssert.AreEquivalent(
            new[] { order1.Id, order2.Id, order3.Id },
            results.Select(o => o.Id).ToArray());
    }

    [TestMethod]
    public void GetOrdersByCustomer_MixedCustomers_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Cable", Price = 10.00m, Quantity = 1 }
        };

        _sut.CreateOrder("alice", items);
        _sut.CreateOrder("bob", items);
        _sut.CreateOrder("alice", items);
        _sut.CreateOrder("charlie", items);

        // Act
        var aliceOrders = _sut.GetOrdersByCustomer("alice");
        var bobOrders = _sut.GetOrdersByCustomer("bob");

        // Assert
        Assert.AreEqual(2, aliceOrders.Count);
        Assert.AreEqual(1, bobOrders.Count);
        Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
        Assert.IsTrue(bobOrders.All(o => o.CustomerId == "bob"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_EmptyStore_ReturnsEmptyList()
    {
        // Act (no orders created)
        var results = _sut.GetOrdersByCustomer("nobody");

        // Assert
        Assert.AreEqual(0, results.Count);
    }
}

